+    await program.parseAsync(["daemon", "start"], { from: "user" });
+    await program.parseAsync(["daemon", "stop"], { from: "user" });
+
+    expect(serviceRestart).toHaveBeenCalledTimes(1);
+    expect(serviceStop).toHaveBeenCalledTimes(1);
+  });
+});

